import Output from 'editorjs-react-renderer';
import { CopyBlock } from 'react-code-blocks';

// Define your custom renderer
// It should expect to receive data, style, classNames and config props. It's up to you to handle those props.
const CustomCodeRenderer = ({ data, style, classNames, config }) => {
  // validate props here...or not :)

  let content = null;

  if (typeof data === 'string') content = data;
  else if (
    typeof data === 'object' &&
    data.code &&
    typeof data.code === 'string'
  )
    content = data.text;

  console.log(data);

  return content ? (
    <CopyBlock
      style={style}
      wrapLines
      showLineNumbers={true}
      text={data}
      className={"code"}
    ></CopyBlock>
  ) : (
    ''
  );
};

const renderers = {
  code: CustomCodeRenderer,
};

export default function EditorjsReact(props) {
  return (
    <section className='blog-post-html'>
      <Output renderers={renderers} data={JSON.parse(props.previousData)} />
    </section>
  );
}
